// Get data and ensure consistent format
const items = $input.all();

// Filter meetings
const calendarEvents = items.filter(item => item.json.kind === 'calendar#event' || item.json.iCalUID);

// Filter emails (not meetings)
const emailMessages = items.filter(item => item.json.threadId && item.json.kind !== 'calendar#event');

// ========== FORMAT MEETINGS ==========
let meetingsText = '';
let meetingsCompleted = 0;
let meetingsUpcoming = 0;
const now = new Date();

for (let i = 0; i < calendarEvents.length; i++) {
  const event = calendarEvents[i].json;
  const startTime = new Date(event.start.dateTime);
  const endTime = new Date(event.end.dateTime);

  const timeRange = `${startTime.getHours().toString().padStart(2,'0')}:${startTime.getMinutes().toString().padStart(2,'0')} - ${endTime.getHours().toString().padStart(2,'0')}:${endTime.getMinutes().toString().padStart(2,'0')}`;

  let status = '';
  if (endTime < now) {
    status = '✓ completed';
    meetingsCompleted++;
  } else if (startTime > now) {
    status = '⏭ upcoming';
    meetingsUpcoming++;
  } else {
    status = '🔴 in progress';
  }

  meetingsText += `• ${timeRange} - ${event.summary} (${status})\n`;
}

if (calendarEvents.length === 0) {
  meetingsText = 'No meetings today';
}

// ========== FORMAT EMAILS ==========
let emailsText = '';
let importantCount = 0;
let importantEmailsList = '';

for (let i = 0; i < emailMessages.length; i++) {
  const email = emailMessages[i].json;

  const isUnread = email.labels && email.labels.includes('UNREAD');

  if (isUnread) {
    importantCount++;
    importantEmailsList += `• ${email.From || email.from}: ${email.Subject || email.subject}\n`;
  }

  emailsText += `• ${email.From || email.from}: ${email.Subject || email.subject}\n`;
}

if (emailMessages.length === 0) {
  emailsText = 'No emails received today';
}

if (importantCount === 0) {
  importantEmailsList = 'No important unread emails';
}

// ========== FORMAT DATE ==========
const today = new Date();
const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

const dateFormatted = `${days[today.getDay()]}, ${today.getDate()} ${months[today.getMonth()]} ${today.getFullYear()}`;

// ========== OUTPUT ==========
return {
  date: dateFormatted,
  meetings_text: meetingsText,
  meetings_total: calendarEvents.length,
  meetings_completed: meetingsCompleted,
  meetings_upcoming: meetingsUpcoming,
  emails_text: emailsText,
  emails_total: emailMessages.length,
  important_count: importantCount,
  important_list: importantEmailsList
};

// Get raw output from AI
const rawOutput = $input.first().json.output;

// Clean the output
const cleanOutput = rawOutput
  .replace(/\\n/g, ' ')
  .replace(/\n/g, ' ')
  .replace(/\s\s+/g, ' ')
  .trim();

// Return as single key
return {
  clean_summary: cleanOutput
};
